-- Pure data seed file — runs after 01_schema.sql on fresh volume
-- DDL here uses IF NOT EXISTS so it's safe if the app also calls init_schema()
-- TimescaleDB internal tables intentionally omitted; managed by the extension

-- ── Tables not created by 01_schema.sql (app creates them, but we need them now) ──

CREATE TABLE IF NOT EXISTS normalized_events (
    job_id UUID,
    timestamp TIMESTAMP WITH TIME ZONE NOT NULL,
    source TEXT NOT NULL,
    event_type TEXT NOT NULL,
    severity TEXT NOT NULL,
    message TEXT NOT NULL,
    ai_category TEXT,
    ai_root_cause TEXT,
    ai_recommended_action TEXT,
    confidence_score FLOAT,
    requires_review BOOLEAN DEFAULT FALSE,
    review_reason TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (job_id, timestamp)
);
SELECT create_hypertable('normalized_events', 'timestamp', if_not_exists => TRUE);

CREATE TABLE IF NOT EXISTS event_routing (
    id BIGSERIAL PRIMARY KEY,
    job_id UUID NOT NULL UNIQUE,
    kafka_topic TEXT NOT NULL,
    routed_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS review_queue_status (
    id BIGSERIAL PRIMARY KEY,
    job_id UUID NOT NULL UNIQUE,
    status TEXT NOT NULL DEFAULT 'pending',
    reviewer_notes TEXT,
    reviewed_at TIMESTAMP WITH TIME ZONE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

